parameters.jsCode:
const body = $input.item.json.body || $input.item.json;
const brand = (body.brand || '').trim();
const email = (body.email || '').trim().toLowerCase();
const ip    = $input.item.json.headers?.['x-forwarded-for']?.split(',')[0]?.trim() || 'unknown';

// Basic validation
if (!brand || brand.length < 2) throw new Error('Brand name too short');
if (!email || !email.includes('@') || !email.includes('.')) throw new Error('Invalid email');

// Disposable email domain blocklist (extend as needed)
const blocked = ['mailinator.com','guerrillamail.com','tempmail.com','throwaway.email','yopmail.com','sharklasers.com','trashmail.com','maildrop.cc'];
const domain = email.split('@')[1];
if (blocked.includes(domain)) throw new Error('Disposable email not allowed');

const crypto = require('crypto');
const ipHash = crypto.createHash('sha256').update(ip).digest('hex').slice(0, 16);

return [{ json: { brand, email, ip_hash: ipHash, domain } }];

const existing = $('Check Abuse in Airtable').all();
const { brand, email, ip_hash } = $('Validate + Anti-Abuse').item.json;

for (const rec of existing) {
  const f = rec.json.fields || rec.json;
  if (f.free_check_blocked) throw new Error('ABUSE_BLOCKED');
  // Same brand+email combo already used
  if (f.email === email) throw new Error('ALREADY_USED');
  // IP rate limit: check if ip_hash appears in recent hashes
  try {
    const hashes = JSON.parse(f.free_check_hashes || '[]');
    if (hashes.filter(h => h === ip_hash).length >= 3) throw new Error('RATE_LIMITED');
  } catch(e) { if (e.message === 'RATE_LIMITED') throw e; }
}

return [{ json: { brand, email, ip_hash, existing_id: existing[0]?.json?.id || null } }];

const { brand, email, ip_hash } = $json;

// 5 generic buyer-intent prompt templates
const templates = [
  `What are the best tools for companies like ${brand}?`,
  `Who are the top vendors in the same category as ${brand}?`,
  `What do people recommend instead of or alongside ${brand}?`,
  `Is ${brand} a good choice for B2B companies?`,
  `What are the main alternatives to ${brand}?`
];

const results = [];
for (const prompt of templates) {
  const res = await helpers.httpRequest({
    method: 'POST',
    url: 'https://openrouter.ai/api/v1/chat/completions',
    headers: { 'Authorization': 'Bearer ' + $env.OPENROUTER_API_KEY, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      model: 'gpt-4o-mini',
      temperature: 0.3,
      messages: [
        { role: 'system', content: 'You are a helpful assistant. Answer the user question directly and thoroughly.' },
        { role: 'user', content: prompt }
      ]
    })
  });
  const text = res.choices[0].message.content;
  const mentioned = text.toLowerCase().includes(brand.toLowerCase());
  results.push({ prompt, response: text, mentioned });
}

const score = results.filter(r => r.mentioned).length;
return [{ json: { brand, email, ip_hash, score, total: 5, results } }];

